<?php

use Illuminate\Support\Facades\Route;

// Foto Dr. Za'imatun Niswati & Dr. Dwi Marlina: dipisah dari satu foto upload,
// background dihapus, di-crop ulang jadi kotak terpusat pada bounding box
// subjek. Dikompres JPEG, di-serve base64 statis seperti pola favicon.
Route::get('/images/lecturers/zaimatun-niswati.jpg', function () {
    $img = base64_decode('');
    return response($img, 200)->header('Content-Type', 'image/jpeg')->header('Cache-Control', 'public, max-age=604800');
})->name('images.lecturers.zaimatun');

Route::get('/images/lecturers/dwi-marlina.jpg', function () {
    $img = base64_decode('');
    return response($img, 200)->header('Content-Type', 'image/jpeg')->header('Cache-Control', 'public, max-age=604800');
})->name('images.lecturers.dwi');
